const Q_CHEMISTRY_2017_MODEL_I=[{"id": "objective>Chemistry>2017-Model-I>1", "question": "<div style=\"font-family:Cambria;font-size:17px;\">What is the basicity of the propanoic acid?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">1</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2</div>", "<div style=\"font-family:Cambria;font-size:17px;\">3</div>", "<div style=\"font-family:Cambria;font-size:17px;\">0</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Propanoic acid is a monoprotic acid, meaning it can donate only one proton per molecule in an aqueous solution. Therefore, its basicity is 1.</div>", "topic": "ACID BASE AND SALTS : ACID AND BASE TITRATIONS"}, {"id": "objective>Chemistry>2017-Model-I>2", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A likely consequence of using fuels with high sulphur content is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Acid rain</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Blood poisoning</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Bore hole </div>", "<div style=\"font-family:Cambria;font-size:17px;\">River water</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">When fuel with Sulphur content is burned, it produces SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> which combines with rain water to form trioxosulphate (iv) and tetraoxosulphate (vi) acid, hence acid rain.</div>", "topic": "ENVIRONMENTAL POLLUTION : AIR POLLUTION"}, {"id": "objective>Chemistry>2017-Model-I>3", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An advantage of detergents over soaps is that detergents </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">are brightly coloured </div>", "<div style=\"font-family:Cambria;font-size:17px;\">are in powdered form</div>", "<div style=\"font-family:Cambria;font-size:17px;\">lather readily with water</div>", "<div style=\"font-family:Cambria;font-size:17px;\">are readily available</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Detergents are more effective than soaps in hard water. Hard water contains ions that react with soap to form a precipitate, which is not useful for cleaning. Detergents, on the other hand, do not form this precipitate and thus lather readily with water.</div>", "topic": "ORGANIC COMPOUNDS : GIANT MOLECULES"}, {"id": "objective>Chemistry>2017-Model-I>4", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following gas is lighter than air?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">CO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">HCl</div>", "<div style=\"font-family:Cambria;font-size:17px;\">NH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span></div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">NH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span> (Ammonia) is lighter than air. Ammonia has a density of 0.73 kg/m<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> whereas the density of air at sea level is 1.225 kg/m<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span>.</div>", "topic": "AIR : GASEOUS CONSTITUENTS"}, {"id": "objective>Chemistry>2017-Model-I>5", "question": "<div style=\"font-family:Cambria;font-size:17px;\">When air is successfully passed through sodium hydroxide solution, alkaline, pyragallol and then concentrated tetraoxosulphate (VI), its remaining components are </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Oxygen and water vapour</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Oxygen and nitrogen</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Carbon (IV) and noble gas </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Nitrogen and rare gases </div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Air contains CO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>, O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>, Water vapour, rare gases and Nitrogen in sufficient amount. <br/> When air is passed through sodium hydroxide solution, alkaline pyrogallol and conc. H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span>, CO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>, O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> and water vapour are removed respectively. Therefore, we are left with Nitrogen and rare gases</div>", "topic": "AIR : GASEOUS CONSTITUENTS"}, {"id": "objective>Chemistry>2017-Model-I>6", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A mixture of chalk and water can be separated by</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">chromatography</div>", "<div style=\"font-family:Cambria;font-size:17px;\">filtration</div>", "<div style=\"font-family:Cambria;font-size:17px;\">separating funnel</div>", "<div style=\"font-family:Cambria;font-size:17px;\">sieving</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A mixture of chalk and water can be separated by filtration. Filtration is a mechanical or physical operation which is used for the separation of solids from fluids (liquids or gases) by interposing a medium through which only the fluid can pass.</div>", "topic": "SEPARATION OF MIXTURES AND PURIFICATION OF CHEMICAL : SEPARATION PROCESS"}, {"id": "objective>Chemistry>2017-Model-I>7", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A physical change is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">fermenting of sugar to ethanol</div>", "<div style=\"font-family:Cambria;font-size:17px;\">rusting of iron</div>", "<div style=\"font-family:Cambria;font-size:17px;\">burning of paper </div>", "<div style=\"font-family:Cambria;font-size:17px;\">dissolving sugar in water</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Dissolution of sugar in water is a reversible process. The sugar can be recovered from sugar solution by evaporation to dryness or by evaporation to dryness or by crystallization. Hence, the process is a physical change.</div>", "topic": "SEPARATION OF MIXTURES AND PURIFICATION OF CHEMICAL : CHEMICAL AND PHYSICAL CHANGES"}, {"id": "objective>Chemistry>2017-Model-I>8", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Chemical equilibrium is based on ......</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">The equality of the rates of the forward and reverse reaction</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The equality of the forward and reverse reactions</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The conditions of two opposing reactions</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The rate of two opposing reactions </div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In a reversible system, when the chemical equilibrium state is reached, the rate of forward reaction is equal to the rate of backward reaction.</div>", "topic": "CHEMICAL EQUILIBRA : DYNAMIC EQUILIBRIUM"}, {"id": "objective>Chemistry>2017-Model-I>9", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">a</span>A<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(g)</span> + <span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">b</span>B<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(g)</span> ⇋ <span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">x</span>G<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(s)</span> + <span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">y</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(g)</span> <br/> The equilibrium constant of the above reaction at a constant temperature is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">(G)(H)<hr size=\"1\" />(A)(B)</td></tr></table></div></div>", "<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">(G)<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">x</span>(H)<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">y</span><hr size=\"1\" />(A)<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">a</span>(B)<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">b</span></td></tr></table></div></div>", "<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">(H)<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">y</span><hr size=\"1\" />(A)<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">a</span>(B)<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">b</span></td></tr></table></div></div>", "<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">(G)<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">x</span><hr size=\"1\" />(A)<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">a</span>(B)<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">b</span></td></tr></table></div></div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The equilibrium constant for a solid specie in a reversible reaction is unity hence, <br/> K<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">SP</span> = [1][H]<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">y</span>/[A]<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">a</span>[B]<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">b</span> <br/>  = [H]<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">y</span>/[A]<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">a</span>[B]<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">b</span></div>", "topic": "CHEMICAL EQUILIBRA : REVERSIBLE REACTIONS"}, {"id": "objective>Chemistry>2017-Model-I>10", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following substances will decompose when an electric current is passed through it.</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Sucrose solution</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Copper rod </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Tetraoxosulphate (VI) solution</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Methylated spirit</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">It is an electrolyte that decomposes when an electrical current is passed through it. The only electrolyte among the options is tetraoxosulphate (VI) acid.</div>", "topic": "ELECTROLYSIS : ELECTROLYTES AND NON-ELECTROLYTES"}, {"id": "objective>Chemistry>2017-Model-I>11", "question": "<div style=\"font-family:Cambria;font-size:17px;\">During the electrolysis of a caustic pottash solution using platinum electrodes </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">alkalinity at the cathode increases </div>", "<div style=\"font-family:Cambria;font-size:17px;\">pottasium metal is deposited at the anode</div>", "<div style=\"font-family:Cambria;font-size:17px;\">pottasium metal is deposited at the cathode</div>", "<div style=\"font-family:Cambria;font-size:17px;\">oxygen gas is given off at the cathode </div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">At the cathode, H<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">+</span>, being lower in the activity series discharges in preference to K<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">+</span>, Hydrogen gas is produced at this electrode. The discharge of H<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">+</span> at this electrode disturbs the ionic equilibrium of water <br/> (H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(l)</span> ⇌ H<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">+</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(aq)</span> + OH<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(aq)</span>) hence, excess OH<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-</span> ions are produced. That is alkalinity increases at this electrode.</div>", "topic": "ELECTROLYSIS : FACTORS AFFECTING DISCHARGE OF IONS AT THE ELECTRODES"}, {"id": "objective>Chemistry>2017-Model-I>12", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which among these has neither charge nor mass?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Alpha particle</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Deuterium </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Gamma ray</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Neutron</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Gamma rays have neither charge nor mass. They are a form of electromagnetic radiation, similar to light or radio waves, and as such, they are massless and carry no charge.</div>", "topic": "ATOMIC STRUCTURE AND BONDING : ATOMIC STRUCTURE ELECTRON CONFIGURATION ATOMIC NUMBER MASS NUMBER AND ISOTOPES"}, {"id": "objective>Chemistry>2017-Model-I>13", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The minimum amount of energy that colliding molecules must reach or possess for their collisions to be successfully known as the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">thermal energy</div>", "<div style=\"font-family:Cambria;font-size:17px;\">collision energy</div>", "<div style=\"font-family:Cambria;font-size:17px;\">activation energy</div>", "<div style=\"font-family:Cambria;font-size:17px;\">kinetic energy</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The minimum amount of energy that colliding molecules must reach or possess for their collisions to be successful is known as the activation energy. It is the energy barrier that must be overcome for a chemical reaction to occur.</div>", "topic": "RATE OF CHEMICAL REACTION : ACTIVATION ENERGY"}, {"id": "objective>Chemistry>2017-Model-I>14", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which among these is generated during the manufacturing of fertilizers?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>S</div>", "<div style=\"font-family:Cambria;font-size:17px;\">CO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">Lead</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Tetraoxosulphate (VI) acid is a primary raw material in the fertilizing industry. Sulphur(IV)oxide is produced in the Process of forming H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span> from sulphur . It is also a by-product in the reation of phosphate rock-with H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span> in the production of superphosphate fertilizer.</div>", "topic": "ENVIRONMENTAL POLLUTION : AIR POLLUTION"}, {"id": "objective>Chemistry>2017-Model-I>15", "question": "<div style=\"font-family:Cambria;font-size:17px;\">What is the empirical formula of an organic compound containing 40.1%C and 6.6%H? <br/> (C = 12, H = 1, O = 16)</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>HO</div>", "<div style=\"font-family:Cambria;font-size:17px;\">CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>O</div>", "<div style=\"font-family:Cambria;font-size:17px;\">CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O</div>", "<div style=\"font-family:Cambria;font-size:17px;\">C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>O</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">% Comp. of Carbon &nbsp &nbsp &nbsp= 40.1 <br/> % Comp. of Hydrogen = 6.6 <br/>  sum of C and H = 46.7% <br/> % comp. of unknown element <br/> or oxygen = (100 - 46.7)% <br/>  = 53.3% <br/> <img src=\"2017-Model-I/8ixwqn.png\" style=\"position:relative;max-width:100%;\"/> <br/> The empirical formula of the organic compound CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O  <br/>  This is glucose.</div>", "topic": "CHEMICAL COMBINATION : THE MOLE CONCEPT AND AVOGADRO'S NUMBER"}, {"id": "objective>Chemistry>2017-Model-I>16", "question": "<div style=\"font-family:Cambria;font-size:17px;\">What is the value of x in Fe(NH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span>)<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>(SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span>)<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> . XH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O if molar mass is 392 gmol<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>? <br/> [Fe = 56, N = 14, S = 32, O = 16, H = 1]</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">2</div>", "<div style=\"font-family:Cambria;font-size:17px;\">4</div>", "<div style=\"font-family:Cambria;font-size:17px;\">5</div>", "<div style=\"font-family:Cambria;font-size:17px;\">6</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Molar mass of the hydrate = 392 gmol<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span> = Fe(NH4)2(SO4)2.XH2O <br/> [56 + 2(18) + 2(96) + x(18)] = 392 <br/> [56 + 36 + 192 + x(18)] = 392 <br/> 284 + 18x = 392 <br/> 18x = 392 - 284 <br/> 18x = 108 <br/> x = 6</div>", "topic": "CHEMICAL COMBINATION : THE MOLE CONCEPT AND AVOGADRO'S NUMBER"}, {"id": "objective>Chemistry>2017-Model-I>17", "question": "<div style=\"font-family:Cambria;font-size:17px;\">What is the percentage composition of Oxygen in K<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>Cr<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">7</span>? <br/> [K<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>Cr<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">7</span> = 294, O = 16, K = 39, Cr = 52]</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">14.20%</div>", "<div style=\"font-family:Cambria;font-size:17px;\">26.53%</div>", "<div style=\"font-family:Cambria;font-size:17px;\">55.27%</div>", "<div style=\"font-family:Cambria;font-size:17px;\">38.10%</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">RMM of K<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>Cr<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">7</span>= 2(39) + 2(52) + 7(16) = 78 + 104 + 112 = 294  <br/> RMM of oxygen = 7(16) = 112  <br/> %Comp. of Oxygen =112/294 ×100 <br/> = 38.095% <br/> = 38.10%</div>", "topic": "CHEMICAL COMBINATION : THE MOLE CONCEPT AND AVOGADRO'S NUMBER"}, {"id": "objective>Chemistry>2017-Model-I>18", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Consider the reaction: 2Al<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(s)</span> + 6H<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">+</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(aq)</span> → 2Al<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3+</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(aq)</span> + 3H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2(g)</span>. What is the total number of moles of electrons transferred from the aluminium atoms to the hydrogen ions?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">3</div>", "<div style=\"font-family:Cambria;font-size:17px;\">4</div>", "<div style=\"font-family:Cambria;font-size:17px;\">5</div>", "<div style=\"font-family:Cambria;font-size:17px;\">6</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Equation of the reaction, <br/> 2Al + 6H<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">+</span> → 2Al<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3+</span> + 3H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> <br/> 2Al - 2(3e<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-</span>) → 2Al<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3+</span> <br/> 2Al → 2Al<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3+</span> + 6e<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-</span> <br/> 6 moles of electrons is transferred to Hydrogen ions.</div>", "topic": "OXIDATION AND REDUCTION : REDUCTION"}, {"id": "objective>Chemistry>2017-Model-I>19", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Metals can be extracted from their ores by a process involving</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Reduction</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Oxidation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Hydrolysis</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Decomposition</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Metals are typically extracted from their ores through a process called reduction. This involves the removal of oxygen from the metal oxide (ore) to yield the pure metal. Hence, the correct option is 1.</div>", "topic": "METALS AND THEIR COMPOUNDS : ALUMINIUM"}, {"id": "objective>Chemistry>2017-Model-I>20", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The solubility of alkanols in water is due to </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">its density</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the presence of hydroxyl group</div>", "<div style=\"font-family:Cambria;font-size:17px;\">its low freezing points </div>", "<div style=\"font-family:Cambria;font-size:17px;\">its volatile nature </div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The solubility of alkanols in water is due to the presence of hydroxyl group and which contributes hydrogen bonding <br/> R - OH</div>", "topic": "ORGANIC COMPOUNDS : ALKANOLS"}, {"id": "objective>Chemistry>2017-Model-I>21", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The Solubility of KHCO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span> is 0.42 moldm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span> at 25°. What is the mass of KHCO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span> in 200cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> of a saturated solution of this salt at 25°C? [KHCO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span> = 100gmol<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>]</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">4.2g</div>", "<div style=\"font-family:Cambria;font-size:17px;\">8.4g</div>", "<div style=\"font-family:Cambria;font-size:17px;\">42g</div>", "<div style=\"font-family:Cambria;font-size:17px;\">84g</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The solubility value (0.42moldm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span>) indicates that: 1000 cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> of solution contains 0.42moldm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span> KHCO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span> therefore 200cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> of solution would contain <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">(</td><td style=\"text-align:center;\">0.42</td><td style=\"text-align:center;\">×</td><td style=\"text-align:center;\">200<hr size=\"1\" />1000</td><td style=\"text-align:center;\">)</td><td style=\"text-align:center;\">mol</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">0.084mol</td><td style=\"text-align:center;\">KHCO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span></td></tr></table></div> <br/> mass of KHCO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span> = Mole × Molar mass <br/>  = (0.084 × 100) = 8.4g</div>", "topic": "ACID BASE AND SALTS : HYDROLYSIS OF SALTS"}, {"id": "objective>Chemistry>2017-Model-I>22", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of these chemical species has no neutron in the nucleus of its atom?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Beryllium ion</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Hydrogen atom</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Lithium ion</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Helium atom</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The hydrogen atom is the only chemical species that has no neutron in the nucleus of its atom. The nucleus of a hydrogen atom consists of only one proton.</div>", "topic": "ATOMIC STRUCTURE AND BONDING : ATOMIC STRUCTURE ELECTRON CONFIGURATION ATOMIC NUMBER MASS NUMBER AND ISOTOPES"}, {"id": "objective>Chemistry>2017-Model-I>23", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Chlorine gas is best collected </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">by upward displacement of air</div>", "<div style=\"font-family:Cambria;font-size:17px;\">by downward displacement of air </div>", "<div style=\"font-family:Cambria;font-size:17px;\">over water</div>", "<div style=\"font-family:Cambria;font-size:17px;\">under water</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Chlorine gas is denser than air hence its collection by downward delivery (upward displacement of air).</div>", "topic": "AIR : GASEOUS CONSTITUENTS"}, {"id": "objective>Chemistry>2017-Model-I>24", "question": "<div style=\"font-family:Cambria;font-size:17px;\">N<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2(g)</span> + 3H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2(g)</span> ⇌ 2NH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3(g)</span> <br/> What role does the finely divided iron play in the Haber process of manufacturing ammonia?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Reducing agent</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Oxidizing agent</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Dehydrating agent</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Catalyzing agent</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In the Haber process, finely divided iron acts as a catalyst. A catalyst is a substance that increases the rate of a chemical reaction without itself undergoing any permanent chemical change.</div>", "topic": "CHEMICAL EQUILIBRA : FACTORS GOVERNING THE EQUILIBRIUM POSITION"}, {"id": "objective>Chemistry>2017-Model-I>25", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following gases can best be collected by downward displacement of air?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Oxygen</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Ammonia</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Sulphur (IV) oxide</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Carbon (IV) oxide</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Ammonia is lighter than air and hence can be collected by downward displacement of air. This means that the ammonia gas will rise and displace the air downwards.</div>", "topic": "AIR : GASEOUS CONSTITUENTS"}, {"id": "objective>Chemistry>2017-Model-I>26", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An oxide which is reduced when heated in a stream of hydrogen is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">K<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O)</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Fe<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">CaO</div>", "<div style=\"font-family:Cambria;font-size:17px;\">CuO</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Hydrogen cannot reduce oxides of metals that stand high in the activity series but can reduce those that are moderately reactive.</div>", "topic": "OXIDATION AND REDUCTION : REDUCTION"}, {"id": "objective>Chemistry>2017-Model-I>27", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which among these is a \"fine\" chemical?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Sodium hydroxide</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Ethanol</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Silver bromide</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Hydrochloric acid</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">\"Fine\" chemical is one that is not commonly used on daily basis. Silver bromide is specially used in the photorgraphic industry while the other chemicals are commonly used in the laboratory.</div>", "topic": "CHEMICAL COMBINATION : STOICHIOMETRY"}, {"id": "objective>Chemistry>2017-Model-I>28", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> Which of the letters indicates elements which exists as diatomic gases?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">B and G</div>", "<div style=\"font-family:Cambria;font-size:17px;\">C and F</div>", "<div style=\"font-family:Cambria;font-size:17px;\">C and A</div>", "<div style=\"font-family:Cambria;font-size:17px;\">A and F</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Diatomic gases from the table given are the elements in group 7 and group 1.</div>", "topic": "ATOMIC STRUCTURE AND BONDING : THE PERIODIC TABLE AND PERIODICITY OF ELEMENTS"}, {"id": "objective>Chemistry>2017-Model-I>29", "question": "<div style=\"font-family:Cambria;font-size:17px;\">What is X in the following reaction? <br/> <span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">14</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">7</span> N + X → <span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">17</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">8</span>O + proton</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Tritium atom</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Neutron</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Deuterium atom</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Alpha particle</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"><span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">14</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">7</span> N + X → <span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">17</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">8</span>O + <span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">1</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>H <br/> 14 + a = 17 + 1 &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp 7 + b = 8 + 1 <br/> 14 + a = 18 &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp 7 + b = 9 <br/> a = 18 - 14 = 4 &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp b = 2 <br/> <span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">a</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">b</span>X = <span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">4</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>He = alpha particles </div>", "topic": "NUCLEAR CHEMISTRY : NUCLEAR REACTIONS"}, {"id": "objective>Chemistry>2017-Model-I>30", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The following statements are true for a co-ordinate covalent bond except</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">It involves sharing of electron  </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Each participating atom contributes one electron</div>", "<div style=\"font-family:Cambria;font-size:17px;\">only one of the participating atoms contributes the two electrons in the bond </div>", "<div style=\"font-family:Cambria;font-size:17px;\">It can be formed between two molecules</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A coordinate covalent bond, also known as a dative bond, is a type of covalent bond in which the two shared electrons originate from the same atom. This atom provides both electrons needed for the bond, unlike in a regular covalent bond where each atom provides one electron. Therefore, the statement 'Each participating atom contributes one electron' is not true for a coordinate covalent bond.</div>", "topic": "ATOMIC STRUCTURE AND BONDING : CHEMICAL BONDING"}, {"id": "objective>Chemistry>2017-Model-I>31", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The Inter atomic bonds present in the sodium trioxocarbonate (IV) compound are </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">metallic and coordinate covalent</div>", "<div style=\"font-family:Cambria;font-size:17px;\">covalent and coordinate covalent</div>", "<div style=\"font-family:Cambria;font-size:17px;\">covalent and electrovalent</div>", "<div style=\"font-family:Cambria;font-size:17px;\">electrovalent and metallic </div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Electrovalent bond between sodium ion and carbonate ion and covalent bonds in the carbonate ions (CO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span><span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2-</span>)</div>", "topic": "ATOMIC STRUCTURE AND BONDING : CHEMICAL BONDING"}, {"id": "objective>Chemistry>2017-Model-I>32", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The ability of an atom to attract electrons towards itself is called</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">electron affinity</div>", "<div style=\"font-family:Cambria;font-size:17px;\">electronegativity</div>", "<div style=\"font-family:Cambria;font-size:17px;\">electropositivity</div>", "<div style=\"font-family:Cambria;font-size:17px;\">ionization energy</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The property of an atom which determines its ability to attract electrons to itself in a bond is called electronegativity <br/>  <br/> Electron affinity is the amount of energy released when one mole of electron is added to a non-metal (in the gaseous state) to form an anion (also in the gaseous state)</div>", "topic": "ATOMIC STRUCTURE AND BONDING : ATOMIC STRUCTURE ELECTRON CONFIGURATION ATOMIC NUMBER MASS NUMBER AND ISOTOPES"}, {"id": "objective>Chemistry>2017-Model-I>33", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The balanced equation of a reaction is  <br/> 2A<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(g)</span> + B<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(g)</span> → E<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(g)</span> <br/> The rate law for the reaction is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">rate = K[A]<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>[B]</div>", "<div style=\"font-family:Cambria;font-size:17px;\">rate = K[A][B]</div>", "<div style=\"font-family:Cambria;font-size:17px;\">rate = K[A]<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">not deducible from the available information</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The rate law of a reaction cannot be deduced from the balanced equation of the reaction. The law is deduced from experimental data.</div>", "topic": "RATE OF CHEMICAL REACTION : FACTORS"}, {"id": "objective>Chemistry>2017-Model-I>34", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In the reaction below, the substance that will increase the rate of production of Ammonia is <br/> N<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2(g)</span> + 3H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2(g)</span> ⇌ 2NH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3(g)</span> </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">platinum</div>", "<div style=\"font-family:Cambria;font-size:17px;\">vanadium (v)oxide</div>", "<div style=\"font-family:Cambria;font-size:17px;\">finely divided nickel</div>", "<div style=\"font-family:Cambria;font-size:17px;\">finely divided iron</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In the Haber process for the production of ammonia (N2(g) + 3H2(g) ⇌ 2NH3(g)), finely divided iron is used as a catalyst to increase the rate of the reaction. A catalyst is a substance that increases the rate of a chemical reaction by providing an alternative reaction pathway with a lower activation energy. It does not change the position of the equilibrium or the energy of the reactants or products.</div>", "topic": "CHEMICAL EQUILIBRA : FACTORS GOVERNING THE EQUILIBRIUM POSITION"}, {"id": "objective>Chemistry>2017-Model-I>35", "question": "<div style=\"font-family:Cambria;font-size:17px;\">At 27°C, 300cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> of a gas sample exerts a pressure of 720mmHg. How many molecules are present in the gas sample? <br/> (N<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">A</span> = 6.02 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">23</span>, R = 0.0821atm dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span>mol<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>k<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>)</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">6.9 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">18</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">6.9 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">19</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">6.9 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">20</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">6.9 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">21</span></div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">From the Ideal gas equation <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">n</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">PV<hr size=\"1\" />RT</td></tr></table></div>,  <br/> number of mole n = ? <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">P</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">Pressure</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">720<hr size=\"1\" />760</td><td style=\"text-align:center;\">atm</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">0.947</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">v</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">volume</td><td style=\"text-align:center;\">of</td><td style=\"text-align:center;\">gases</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">300<hr size=\"1\" />1000</td><td style=\"text-align:center;\">dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">0.3dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span></td></tr></table></div> <br/> T = (27 + 273)K = 300K <br/> R = 0.0821 atm dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span>mol<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>k<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">n</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">0.947×0.3<hr size=\"1\" />0.0821×</td><td style=\"text-align:center;\">300</td><td style=\"text-align:center;\">mol</td></tr></table></div> <br/> n = 0.0115mol <br/> 1 mole of the gas contains 6.02 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">23</span> molecules  <br/> 0.0115 mole of gas would contain (0.0115 × 6.02 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">23</span>) <br/>  = 6.9 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">21</span> molecules</div>", "topic": "KINETIC THEORY OF MATTER AND GAS LAWS : AN OUTLINE OF THE KINETIC THEORY OF MATTER"}, {"id": "objective>Chemistry>2017-Model-I>36", "question": "<div style=\"font-family:Cambria;font-size:17px;\">What do polymorphs have in common?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Melting point</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Solubility</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Chemical reactions </div>", "<div style=\"font-family:Cambria;font-size:17px;\">State of matter</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Polymorphism is the ability of a solid material to exist in two or more forms or crystalline structures of the same chemical compound and it is a solid state phenomena. Polymorphism can found in any crystalline material like polymers, minerals, and metals. They may differ in physical appearance and properties, but would have the same chemical properties.</div>", "topic": "ORGANIC COMPOUNDS : GIANT MOLECULES"}, {"id": "objective>Chemistry>2017-Model-I>37", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The complete hydrogenation of benzene gives</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">cyclohexene</div>", "<div style=\"font-family:Cambria;font-size:17px;\">cyclohexane</div>", "<div style=\"font-family:Cambria;font-size:17px;\">hexene</div>", "<div style=\"font-family:Cambria;font-size:17px;\">hexane</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Hydrogenation is a chemical reaction between molecular hydrogen (H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>) and another compound or element, usually in the presence of a catalyst. The process of hydrogenation involves the addition of hydrogen (H2). When benzene undergoes complete hydrogenation, it becomes cyclohexane. This is because the benzene ring is fully saturated with hydrogen atoms, converting the ring structure into a cyclohexane structure.</div>", "topic": "ORGANIC COMPOUNDS : GIANT MOLECULES"}, {"id": "objective>Chemistry>2017-Model-I>38", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following ammonium salt is used in the manufacture of dry cells?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">(NH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span>)<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">NH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span>Cl</div>", "<div style=\"font-family:Cambria;font-size:17px;\">(NH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span>)<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>CO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">NH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span>NO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span></div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">NH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span>Cl (in form of paste or jelly mixed with starch or flour serves as the electrolytes in dry cells e.g Leclanche cell.</div>", "topic": "ACID BASE AND SALTS : GENERAL CHARACTERISTICS AND PROPERTIES"}, {"id": "objective>Chemistry>2017-Model-I>39", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following reagent will remove CO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> from a mixture of CO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> and N<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">bromine water </div>", "<div style=\"font-family:Cambria;font-size:17px;\">concentrated H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">alkaline pyrogallol</div>", "<div style=\"font-family:Cambria;font-size:17px;\">aqueous KOH</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Aqueous KOH (Potassium hydroxide) is used to remove CO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> from a mixture of CO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> and N<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>. This is because KOH reacts with CO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> to form potassium carbonate and water, effectively removing the CO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> from the mixture.</div>", "topic": "CHEMICAL EQUILIBRA : REVERSIBLE REACTIONS"}, {"id": "objective>Chemistry>2017-Model-I>40", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The oxidation number of chlorine is +1 in </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">HCl</div>", "<div style=\"font-family:Cambria;font-size:17px;\">KClO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">NaCl</div>", "<div style=\"font-family:Cambria;font-size:17px;\">NaClO</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The oxidation number of chlorine in NaClO (Sodium hypochlorite) is +1. Oxidation number is a concept in chemistry that helps in understanding the oxidation and reduction reactions. It is the charge that an atom would have if the compound was composed of ions.</div>", "topic": "OXIDATION AND REDUCTION : OXIDATION"}];
